#include "ai_factory/cuda/g2_plus_plus/bermudan_swaptions.cuh"
#include "ai_factory/common/fixed_income/g2_plus_plus.hpp"
#include "ai_factory/cuda/common/bermudan_lsm.cuh"
#include "ai_factory/cuda/common/philox.cuh"
#include "ai_factory/cuda/common/runtime.cuh"
namespace ai_factory::cuda {namespace {constexpr std::size_t kMaxExercises=bermudan_lsm::kMaxExercises,kMaxPayments=20,kRowsPerBatch=128;constexpr double kBasisScale=.04;struct Tag{};
__global__ void precompute(const G2PlusPlusBermudanSwaptionRow*rows,std::size_t count,int*counts,fixed_income::G2Transition*transitions,double*ba,double*bbx,double*bby){const auto ri=static_cast<std::size_t>(blockIdx.x);if(ri>=count)return;const auto r=rows[ri];const auto&m=r.model;const auto&p=r.product;if(threadIdx.x==0)counts[ri]=p.exercise_count;if(threadIdx.x<p.exercise_count){const auto e=static_cast<std::size_t>(threadIdx.x);const double time=p.first_exercise+e*p.exercise_period;const double previous=e? p.first_exercise+(e-1)*p.exercise_period:0;transitions[ri*kMaxExercises+e]=fixed_income::make_g2_transition(m.mean_reversion_x,m.volatility_x,m.mean_reversion_y,m.volatility_y,m.rho,time-previous);}for(std::size_t flat=threadIdx.x;flat<kMaxExercises*kMaxPayments;flat+=blockDim.x){const auto e=flat/kMaxPayments,j=flat%kMaxPayments,index=(ri*kMaxExercises+e)*kMaxPayments+j;if(e<static_cast<std::size_t>(p.exercise_count)&&j>=e&&j<static_cast<std::size_t>(p.payment_count)){const double time=p.first_exercise+e*p.exercise_period,maturity=p.first_exercise+(j+1)*p.accrual_period;ba[index]=fixed_income::g2_bond_price(0,0,time,maturity,m.mean_reversion_x,m.volatility_x,m.mean_reversion_y,m.volatility_y,m.rho,r.curve.beta0,r.curve.beta1,r.curve.beta2,r.curve.tau);bbx[index]=fixed_income::ou_b(m.mean_reversion_x,maturity-time);bby[index]=fixed_income::ou_b(m.mean_reversion_y,maturity-time);}else{ba[index]=bbx[index]=bby[index]=0;}}}
__global__ void simulate(const G2PlusPlusBermudanSwaptionRow*rows,std::size_t count,std::size_t paths,const fixed_income::G2Transition*transitions,const double*ba,const double*bbx,const double*bby,double*immediate,double*basis,double*discounts){const auto ri=static_cast<std::size_t>(blockIdx.x);if(ri>=count)return;const auto r=rows[ri];const auto&m=r.model;const auto&p=r.product;for(std::size_t path=threadIdx.x;path<paths;path+=blockDim.x){double x=0,y=0,ix=0,iy=0;for(int e=0;e<p.exercise_count;++e){fixed_income::apply_g2_transition(transitions[ri*kMaxExercises+e],rng::standard_normal(r.seed,0U,path*4U*static_cast<std::size_t>(p.exercise_count)+4U*static_cast<std::size_t>(e)),rng::standard_normal(r.seed,0U,path*4U*static_cast<std::size_t>(p.exercise_count)+4U*static_cast<std::size_t>(e)+1U),rng::standard_normal(r.seed,0U,path*4U*static_cast<std::size_t>(p.exercise_count)+4U*static_cast<std::size_t>(e)+2U),rng::standard_normal(r.seed,0U,path*4U*static_cast<std::size_t>(p.exercise_count)+4U*static_cast<std::size_t>(e)+3U),x,y,ix,iy);const auto offset=(ri*kMaxExercises+e)*kMaxPayments;double annuity=0,end=1;for(int j=e;j<p.payment_count;++j){const double bond=ba[offset+j]*exp(-bbx[offset+j]*x-bby[offset+j]*y);annuity+=p.accrual_period*bond;end=bond;}const auto out=(ri*kMaxExercises+e)*paths+path;const double swap=static_cast<double>(p.direction)*(1-end-p.fixed_rate*annuity);immediate[out]=p.notional*fmax(swap,0.0);basis[out]=(1-end)/annuity/kBasisScale;const double time=p.first_exercise+e*p.exercise_period;discounts[out]=fixed_income::g2_path_discount(ix,iy,time,m.mean_reversion_x,m.volatility_x,m.mean_reversion_y,m.volatility_y,m.rho,r.curve.beta0,r.curve.beta1,r.curve.beta2,r.curve.tau);}}}
}
void price_g2_plus_plus_bermudan_swaption_cuda(const G2PlusPlusBermudanSwaptionRow*host,std::size_t count,std::size_t paths,MonteCarloOutput*out,CudaTiming*t){if(!count)return;auto&w=detail::reusable_cuda_workspace<Tag,14>();const auto capacity=count<kRowsPerBatch?count:kRowsPerBatch;auto*rows=w.buffer<G2PlusPlusBermudanSwaptionRow>(0,capacity,"G2++ Bermudan rows");auto*counts=w.buffer<int>(1,capacity,"counts");auto*transitions=w.buffer<fixed_income::G2Transition>(2,capacity*kMaxExercises,"transitions");auto*ba=w.buffer<double>(3,capacity*kMaxExercises*kMaxPayments,"bond a");auto*bbx=w.buffer<double>(4,capacity*kMaxExercises*kMaxPayments,"bond bx");auto*bby=w.buffer<double>(5,capacity*kMaxExercises*kMaxPayments,"bond by");const auto states=capacity*kMaxExercises*paths;auto*immediate=w.buffer<double>(6,states,"immediate");auto*basis=w.buffer<double>(7,states,"basis");auto*discounts=w.buffer<double>(8,states,"discounts");auto*cashflows=w.buffer<double>(9,capacity*paths,"cashflows");auto*stats=w.buffer<double>(10,capacity*bermudan_lsm::kStatCount,"stats");auto*coefficients=w.buffer<double>(11,capacity*(bermudan_lsm::kBasisSize+1),"coefficients");auto*outputs=w.buffer<MonteCarloOutput>(12,capacity,"outputs");float total=0;for(std::size_t offset=0;offset<count;offset+=capacity){const auto batch=(count-offset)<capacity?(count-offset):capacity;detail::check_cuda(cudaMemcpy(rows,host+offset,batch*sizeof(*rows),cudaMemcpyHostToDevice),"copy rows");detail::check_cuda(cudaEventRecord(w.start_event()),"start");precompute<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock>>>(rows,batch,counts,transitions,ba,bbx,bby);simulate<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock>>>(rows,batch,paths,transitions,ba,bbx,bby,immediate,basis,discounts);bermudan_lsm::initialize_cashflows_kernel<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock>>>(counts,immediate,discounts,batch,paths,cashflows);const auto shared=bermudan_lsm::kStatCount*detail::kThreadsPerBlock*sizeof(double);for(std::size_t e=kMaxExercises-1;e-->0;){bermudan_lsm::regression_stats_kernel<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock,shared>>>(counts,immediate,basis,discounts,cashflows,batch,paths,e,stats);bermudan_lsm::solve_kernel<<<static_cast<unsigned>(batch),1>>>(stats,batch,coefficients);bermudan_lsm::apply_exercise_kernel<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock>>>(counts,immediate,basis,discounts,coefficients,batch,paths,e,cashflows);}bermudan_lsm::finalize_kernel<<<static_cast<unsigned>(batch),detail::kThreadsPerBlock,2*detail::kThreadsPerBlock*sizeof(double)>>>(cashflows,batch,paths,outputs);detail::check_cuda(cudaGetLastError(),"G2++ Bermudan kernels");detail::check_cuda(cudaEventRecord(w.stop_event()),"stop");detail::check_cuda(cudaEventSynchronize(w.stop_event()),"sync");float ms=0;detail::check_cuda(cudaEventElapsedTime(&ms,w.start_event(),w.stop_event()),"elapsed");total+=ms;detail::check_cuda(cudaMemcpy(out+offset,outputs,batch*sizeof(*outputs),cudaMemcpyDeviceToHost),"copy outputs");}if(t){t->simulation_ms=total;t->total_ms=total;}}
}
